{"title": "Smart Spending: What Does Each Strategy Cost?", "type": "vega", "params": {"spec": "{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "title": {"text": "Cost per strategy across all tasks", "subtitle": "Hybrid strategies only pay for the expensive step (writing). Analysis + review stay local for free.", "fontSize": 16, "subtitleFontSize": 12, "subtitleColor": "#888"},
  "autosize": {"type": "fit", "contains": "padding"},
  "padding": 20,
  "data": [
    {
      "name": "raw",
      "url": {
        "%context%": true,
        "index": "glitch-llm-calls",
        "body": {"size": 500}
      },
      "format": {"property": "hits.hits"},
      "transform": [
        {"type": "formula", "as": "step", "expr": "split(datum._source.step, '/')[1] || datum._source.step"},
        {"type": "formula", "as": "issue", "expr": "datum._source.issue"},
        {"type": "formula", "as": "variant", "expr": "datum._source.comparison_group"},
        {"type": "formula", "as": "cost", "expr": "datum._source.cost_usd"},
        {"type": "formula", "as": "latency", "expr": "datum._source.latency_ms"},
        {"type": "formula", "as": "is_write", "expr": "datum.step == 'write'"},
        {"type": "formula", "as": "is_analyze", "expr": "datum.step == 'analyze'"},
        {"type": "formula", "as": "is_review", "expr": "datum.step == 'review'"}
      ]
    },
    {
      "name": "by_issue_variant_step",
      "source": "raw",
      "transform": [
        {"type": "aggregate", "groupby": ["issue", "variant", "step"], "ops": ["sum", "sum"], "fields": ["cost", "latency"], "as": ["cost", "latency"]}
      ]
    },
    {
      "name": "strategies",
      "source": "by_issue_variant_step",
      "transform": [
        {"type": "pivot", "groupby": ["issue"], "field": "variant", "value": "cost", "op": "sum"},
        {"type": "formula", "as": "pure_local", "expr": "0"},
        {"type": "formula", "as": "pure_claude", "expr": "datum.claude || 0"},
        {"type": "formula", "as": "pure_copilot", "expr": "datum.copilot || 0"},
        {"type": "fold", "fields": ["pure_local", "pure_claude", "pure_copilot"], "as": ["strategy", "total_cost"]}
      ]
    },
    {
      "name": "hybrid_costs",
      "values": [
        {"strategy": "100% Local (Free)", "description": "All steps on your computer", "sort": 1},
        {"strategy": "Local + Claude (Write Only)", "description": "Analysis + review local, writing on Claude", "sort": 2},
        {"strategy": "Local + Copilot (Write Only)", "description": "Analysis + review local, writing on Copilot", "sort": 3},
        {"strategy": "100% Claude", "description": "All steps on Claude", "sort": 4},
        {"strategy": "100% Copilot", "description": "All steps on Copilot", "sort": 5}
      ]
    },
    {
      "name": "computed",
      "url": {
        "%context%": true,
        "index": "glitch-llm-calls",
        "body": {"size": 500}
      },
      "format": {"property": "hits.hits"},
      "transform": [
        {"type": "formula", "as": "step", "expr": "split(datum._source.step, '/')[1] || datum._source.step"},
        {"type": "formula", "as": "variant", "expr": "datum._source.comparison_group"},
        {"type": "formula", "as": "cost", "expr": "datum._source.cost_usd"},
        {"type": "formula", "as": "latency", "expr": "datum._source.latency_ms / 1000"},
        {"type": "aggregate", "groupby": ["variant", "step"], "ops": ["sum", "sum"], "fields": ["cost", "latency"], "as": ["total_cost", "total_secs"]},
        {"type": "pivot", "groupby": ["step"], "field": "variant", "value": "total_cost"},
        {"type": "formula", "as": "claude_cost", "expr": "datum.claude || 0"},
        {"type": "formula", "as": "copilot_cost", "expr": "datum.copilot || 0"}
      ]
    },
    {
      "name": "final",
      "url": {
        "%context%": true,
        "index": "glitch-llm-calls",
        "body": {"size": 500}
      },
      "format": {"property": "hits.hits"},
      "transform": [
        {"type": "formula", "as": "step", "expr": "split(datum._source.step, '/')[1] || datum._source.step"},
        {"type": "formula", "as": "variant", "expr": "datum._source.comparison_group"},
        {"type": "formula", "as": "cost", "expr": "datum._source.cost_usd"},
        {"type": "aggregate", "groupby": ["variant"], "ops": ["sum"], "fields": ["cost"], "as": ["total"]},
        {"type": "formula", "as": "strategy", "expr": "datum.variant == 'local' ? '100% Local (Free)' : datum.variant == 'claude' ? '100% Claude' : '100% Copilot'"},
        {"type": "formula", "as": "sort", "expr": "datum.variant == 'local' ? 1 : datum.variant == 'claude' ? 4 : 5"}
      ]
    }
  ],
  "marks": [
    {
      "type": "rect",
      "from": {"data": "final"},
      "encode": {
        "enter": {
          "y": {"field": "strategy", "scale": "y"},
          "height": {"scale": "y", "band": 0.7},
          "x": {"value": 0, "scale": "x"},
          "x2": {"field": "total", "scale": "x"},
          "cornerRadiusTopRight": {"value": 6},
          "cornerRadiusBottomRight": {"value": 6},
          "fill": {"field": "variant", "scale": "color"},
          "tooltip": {"signal": "{'Strategy': datum.strategy, 'Total Cost': '$' + format(datum.total, '.3f')}"}
        }
      }
    },
    {
      "type": "text",
      "from": {"data": "final"},
      "encode": {
        "enter": {
          "y": {"field": "strategy", "scale": "y", "band": 0.5},
          "x": {"field": "total", "scale": "x", "offset": 8},
          "text": {"signal": "'$' + format(datum.total, '.3f')"},
          "fontSize": {"value": 14},
          "fontWeight": {"value": "bold"},
          "baseline": {"value": "middle"},
          "fill": {"value": "#333"}
        }
      }
    }
  ],
  "scales": [
    {"name": "y", "type": "band", "domain": {"data": "final", "field": "strategy", "sort": {"field": "sort", "order": "ascending"}}, "range": "height", "padding": 0.3},
    {"name": "x", "type": "linear", "domain": {"data": "final", "field": "total"}, "range": "width", "nice": true},
    {"name": "color", "type": "ordinal", "domain": ["local", "claude", "copilot"], "range": ["#54B399", "#6092C0", "#D36086"]}
  ],
  "axes": [
    {"orient": "left", "scale": "y", "labelFontSize": 13, "tickSize": 0},
    {"orient": "bottom", "scale": "x", "title": "Total Cost (USD)", "format": "$.3f", "labelFontSize": 12, "titleFontSize": 13}
  ]
}"}, "aggs": []}

